import uuid
import hashlib
import time
import threading
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Tuple, Any


# --- Dependency Management ---

class FeatureStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class DependencyManager:
    """Manages feature dependencies ensuring proper initialization order."""

    def __init__(self):
        self._features: Dict[str, FeatureStatus] = {}
        self._dependencies: Dict[str, List[str]] = {}
        self._lock = threading.Lock()

    def register_feature(self, feature_name: str, dependencies: Optional[List[str]] = None):
        with self._lock:
            self._features[feature_name] = FeatureStatus.NOT_STARTED
            self._dependencies[feature_name] = dependencies or []

    def activate_feature(self, feature_name: str) -> bool:
        with self._lock:
            if feature_name not in self._features:
                return False
            for dep in self._dependencies[feature_name]:
                if self._features.get(dep) != FeatureStatus.COMPLETED:
                    return False
            self._features[feature_name] = FeatureStatus.IN_PROGRESS
            return True

    def complete_feature(self, feature_name: str) -> bool:
        with self._lock:
            if self._features.get(feature_name) == FeatureStatus.IN_PROGRESS:
                self._features[feature_name] = FeatureStatus.COMPLETED
                return True
            return False

    def is_available(self, feature_name: str) -> bool:
        with self._lock:
            return self._features.get(feature_name) == FeatureStatus.COMPLETED

    def get_status(self, feature_name: str) -> Optional[FeatureStatus]:
        with self._lock:
            return self._features.get(feature_name)

    def get_unmet_dependencies(self, feature_name: str) -> List[str]:
        with self._lock:
            unmet = []
            for dep in self._dependencies.get(feature_name, []):
                if self._features.get(dep) != FeatureStatus.COMPLETED:
                    unmet.append(dep)
            return unmet


# --- User Registration and Authentication ---

class User:
    """Represents a registered designer."""

    def __init__(self, username: str, email: str, password_hash: str):
        self.user_id: str = str(uuid.uuid4())
        self.username: str = username
        self.email: str = email
        self.password_hash: str = password_hash
        self.created_at: datetime = datetime.now()
        self.is_active: bool = True
        self.session_token: Optional[str] = None

    def __repr__(self):
        return f"User(username='{self.username}', email='{self.email}')"


class AuthenticationSystem:
    """Handles user registration, login, and session management."""

    def __init__(self, dependency_manager: DependencyManager):
        self._users: Dict[str, User] = {}
        self._sessions: Dict[str, str] = {}
        self._lock = threading.Lock()
        self._dependency_manager = dependency_manager

    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def _generate_token(self) -> str:
        return str(uuid.uuid4())

    def register(self, username: str, email: str, password: str) -> Optional[User]:
        with self._lock:
            if username in self._users:
                return None
            for user in self._users.values():
                if user.email == email:
                    return None
            password_hash = self._hash_password(password)
            user = User(username, email, password_hash)
            self._users[username] = user
            return user

    def login(self, username: str, password: str) -> Optional[str]:
        with self._lock:
            user = self._users.get(username)
            if not user or not user.is_active:
                return None
            if user.password_hash != self._hash_password(password):
                return None
            token = self._generate_token()
            user.session_token = token
            self._sessions[token] = username
            return token

    def logout(self, token: str) -> bool:
        with self._lock:
            username = self._sessions.pop(token, None)
            if username and username in self._users:
                self._users[username].session_token = None
                return True
            return False

    def validate_session(self, token: str) -> Optional[User]:
        with self._lock:
            username = self._sessions.get(token)
            if username:
                return self._users.get(username)
            return None

    def get_user(self, username: str) -> Optional[User]:
        return self._users.get(username)

    def get_active_users(self) -> List[User]:
        return [u for u in self._users.values() if u.session_token is not None]


# --- Shape and Texture Tools ---

class ShapeType(Enum):
    RECTANGLE = "rectangle"
    CIRCLE = "circle"
    TRIANGLE = "triangle"
    LINE = "line"
    POLYGON = "polygon"
    ELLIPSE = "ellipse"


class Texture:
    """Represents a texture that can be applied to shapes."""

    def __init__(self, name: str, pattern: str, color: str, opacity: float = 1.0):
        self.texture_id: str = str(uuid.uuid4())
        self.name: str = name
        self.pattern: str = pattern
        self.color: str = color
        self.opacity: float = max(0.0, min(1.0, opacity))

    def __repr__(self):
        return f"Texture(name='{self.name}', pattern='{self.pattern}')"


class Shape:
    """Represents a geometric shape on the canvas."""

    def __init__(self, shape_type: ShapeType, x: float, y: float,
                 width: float, height: float, creator_id: str):
        self.shape_id: str = str(uuid.uuid4())
        self.shape_type: ShapeType = shape_type
        self.x: float = x
        self.y: float = y
        self.width: float = width
        self.height: float = height
        self.rotation: float = 0.0
        self.fill_color: str = "#FFFFFF"
        self.stroke_color: str = "#000000"
        self.stroke_width: float = 1.0
        self.texture: Optional[Texture] = None
        self.creator_id: str = creator_id
        self.created_at: datetime = datetime.now()
        self.modified_at: datetime = datetime.now()
        self.is_locked: bool = False
        self.layer: int = 0
        self.group_id: Optional[str] = None
        self.visible: bool = True

    def move(self, dx: float, dy: float):
        self.x += dx
        self.y += dy
        self.modified_at = datetime.now()

    def resize(self, width: float, height: float):
        self.width = width
        self.height = height
        self.modified_at = datetime.now()

    def rotate(self, angle: float):
        self.rotation = (self.rotation + angle) % 360
        self.modified_at = datetime.now()

    def apply_texture(self, texture: Texture):
        self.texture = texture
        self.modified_at = datetime.now()

    def remove_texture(self):
        self.texture = None
        self.modified_at = datetime.now()

    def set_fill(self, color: str):
        self.fill_color = color
        self.modified_at = datetime.now()

    def set_stroke(self, color: str, width: float = 1.0):
        self.stroke_color = color
        self.stroke_width = width
        self.modified_at = datetime.now()

    def __repr__(self):
        return (f"Shape(type={self.shape_type.value}, "
                f"pos=({self.x},{self.y}), size=({self.width},{self.height}))")


class ShapeToolkit:
    """Provides tools for creating and managing shapes and textures."""

    def __init__(self, dependency_manager: DependencyManager):
        self._textures: Dict[str, Texture] = {}
        self._lock = threading.Lock()
        self._dependency_manager = dependency_manager

    def create_shape(self, shape_type: ShapeType, x: float, y: float,
                     width: float, height: float, creator_id: str) -> Optional[Shape]:
        if not self._dependency_manager.is_available("shape_tools"):
            return None
        return Shape(shape_type, x, y, width, height, creator_id)

    def create_texture(self, name: str, pattern: str, color: str,
                       opacity: float = 1.0) -> Texture:
        texture = Texture(name, pattern, color, opacity)
        with self._lock:
            self._textures[texture.texture_id] = texture
        return texture

    def apply_texture_to_shape(self, shape: Shape, texture_id: str) -> bool:
        if not self._dependency_manager.is_available("shape_tools"):
            return False
        with self._lock:
            texture = self._textures.get(texture_id)
        if texture and shape:
            shape.apply_texture(texture)
            return True
        return False

    def get_texture(self, texture_id: str) -> Optional[Texture]:
        with self._lock:
            return self._textures.get(texture_id)

    def list_textures(self) -> List[Texture]:
        with self._lock:
            return list(self._textures.values())

    def delete_texture(self, texture_id: str) -> bool:
        with self._lock:
            return self._textures.pop(texture_id, None) is not None


# --- Element Management and Organization ---

class ElementGroup:
    """Represents a group of design elements."""

    def __init__(self, name: str, creator_id: str):
        self.group_id: str = str(uuid.uuid4())
        self.name: str = name
        self.creator_id: str = creator_id
        self.element_ids: List[str] = []
        self.created_at: datetime = datetime.now()

    def add_element(self, element_id: str):
        if element_id not in self.element_ids:
            self.element_ids.append(element_id)

    def remove_element(self, element_id: str):
        if element_id in self.element_ids:
            self.element_ids.remove(element_id)

    def __repr__(self):
        return f"ElementGroup(name='{self.name}', elements={len(self.element_ids)})"


class AlignmentType(Enum):
    LEFT = "left"
    RIGHT = "right"
    TOP = "top"
    BOTTOM = "bottom"
    CENTER_H = "center_horizontal"
    CENTER_V = "center_vertical"
    DISTRIBUTE_H = "distribute_horizontal"
    DISTRIBUTE_V = "distribute_vertical"


class ElementManager:
    """Manages alignment, grouping, and arrangement of design elements."""

    def __init__(self, dependency_manager: DependencyManager):
        self._groups: Dict[str, ElementGroup] = {}
        self._lock = threading.Lock()
        self._dependency_manager = dependency_manager

    def is_available(self) -> bool:
        return self._dependency_manager.is_available("element_management")

    def create_group(self, name: str, creator_id: str,
                     shapes: Optional[List[Shape]] = None) -> Optional[ElementGroup]:
        if not self.is_available():
            return None
        group = ElementGroup(name, creator_id)
        if shapes:
            for shape in shapes:
                shape.group_id = group.group_id
                group.add_element(shape.shape_id)
        with self._lock:
            self._groups[group.group_id] = group
        return group

    def ungroup(self, group_id: str, shapes: List[Shape]) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            group = self._groups.pop(group_id, None)
        if group:
            for shape in shapes:
                if shape.group_id == group_id:
                    shape.group_id = None
            return True
        return False

    def align_shapes(self, shapes: List[Shape],
                     alignment: AlignmentType) -> bool:
        if not self.is_available() or not shapes:
            return False

        if alignment == AlignmentType.LEFT:
            min_x = min(s.x for s in shapes)
            for s in shapes:
                s.x = min_x
                s.modified_at = datetime.now()
        elif alignment == AlignmentType.RIGHT:
            max_x = max(s.x + s.width for s in shapes)
            for s in shapes:
                s.x = max_x - s.width
                s.modified_at = datetime.now()
        elif alignment == AlignmentType.TOP:
            min_y = min(s.y for s in shapes)
            for s in shapes:
                s.y = min_y
                s.modified_at = datetime.now()
        elif alignment == AlignmentType.BOTTOM:
            max_y = max(s.y + s.height for s in shapes)
            for s in shapes:
                s.y = max_y - s.height
                s.modified_at = datetime.now()
        elif alignment == AlignmentType.CENTER_H:
            center = sum(s.x + s.width / 2 for s in shapes) / len(shapes)
            for s in shapes:
                s.x = center - s.width / 2
                s.modified_at = datetime.now()
        elif alignment == AlignmentType.CENTER_V:
            center = sum(s.y + s.height / 2 for s in shapes) / len(shapes)
            for s in shapes:
                s.y = center - s.height / 2
                s.modified_at = datetime.now()
        elif alignment == AlignmentType.DISTRIBUTE_H:
            if len(shapes) < 3:
                return True
            sorted_shapes = sorted(shapes, key=lambda s: s.x)
            total_width = sum(s.width for s in sorted_shapes)
            span = (sorted_shapes[-1].x + sorted_shapes[-1].width) - sorted_shapes[0].x
            gap = (span - total_width) / (len(sorted_shapes) - 1)
            current_x = sorted_shapes[0].x
            for s in sorted_shapes:
                s.x = current_x
                current_x += s.width + gap
                s.modified_at = datetime.now()
        elif alignment == AlignmentType.DISTRIBUTE_V:
            if len(shapes) < 3:
                return True
            sorted_shapes = sorted(shapes, key=lambda s: s.y)
            total_height = sum(s.height for s in sorted_shapes)
            span = (sorted_shapes[-1].y + sorted_shapes[-1].height) - sorted_shapes[0].y
            gap = (span - total_height) / (len(sorted_shapes) - 1)
            current_y = sorted_shapes[0].y
            for s in sorted_shapes:
                s.y = current_y
                current_y += s.height + gap
                s.modified_at = datetime.now()
        return True

    def arrange_layer(self, shape: Shape, layer: int) -> bool:
        if not self.is_available():
            return False
        shape.layer = layer
        shape.modified_at = datetime.now()
        return True

    def bring_to_front(self, shape: Shape, all_shapes: List[Shape]) -> bool:
        if not self.is_available():
            return False
        max_layer = max((s.layer for s in all_shapes), default=0)
        shape.layer = max_layer + 1
        shape.modified_at = datetime.now()
        return True

    def send_to_back(self, shape: Shape, all_shapes: List[Shape]) -> bool:
        if not self.is_available():
            return False
        min_layer = min((s.layer for s in all_shapes), default=0)
        shape.layer = min_layer - 1
        shape.modified_at = datetime.now()
        return True

    def get_group(self, group_id: str) -> Optional[ElementGroup]:
        with self._lock:
            return self._groups.get(group_id)

    def list_groups(self) -> List[ElementGroup]:
        with self._lock:
            return list(self._groups.values())


# --- Annotation and Commenting System ---

class Annotation:
    """Represents an annotation or comment on the canvas."""

    def __init__(self, content: str, author_id: str, x: float, y: float,
                 target_shape_id: Optional[str] = None):
        self.annotation_id: str = str(uuid.uuid4())
        self.content: str = content
        self.author_id: str = author_id
        self.x: float = x
        self.y: float = y
        self.target_shape_id: Optional[str] = target_shape_id
        self.created_at: datetime = datetime.now()
        self.modified_at: datetime = datetime.now()
        self.resolved: bool = False
        self.replies: List['AnnotationReply'] = []

    def edit(self, new_content: str):
        self.content = new_content
        self.modified_at = datetime.now()

    def resolve(self):
        self.resolved = True
        self.modified_at = datetime.now()

    def unresolve(self):
        self.resolved = False
        self.modified_at = datetime.now()

    def add_reply(self, content: str, author_id: str) -> 'AnnotationReply':
        reply = AnnotationReply(content, author_id, self.annotation_id)
        self.replies.append(reply)
        self.modified_at = datetime.now()
        return reply

    def __repr__(self):
        return (f"Annotation(author='{self.author_id}', "
                f"content='{self.content[:30]}...', resolved={self.resolved})")


class AnnotationReply:
    """Represents a reply to an annotation."""

    def __init__(self, content: str, author_id: str, parent_annotation_id: str):
        self.reply_id: str = str(uuid.uuid4())
        self.content: str = content
        self.author_id: str = author_id
        self.parent_annotation_id: str = parent_annotation_id
        self.created_at: datetime = datetime.now()

    def __repr__(self):
        return f"AnnotationReply(author='{self.author_id}', content='{self.content[:30]}...')"


class AnnotationSystem:
    """Manages annotations and comments on the canvas."""

    def __init__(self, dependency_manager: DependencyManager):
        self._annotations: Dict[str, Annotation] = {}
        self._lock = threading.Lock()
        self._dependency_manager = dependency_manager

    def is_available(self) -> bool:
        return self._dependency_manager.is_available("annotation_system")

    def add_annotation(self, content: str, author_id: str, x: float, y: float,
                       target_shape_id: Optional[str] = None) -> Optional[Annotation]:
        if not self.is_available():
            return None
        annotation = Annotation(content, author_id, x, y, target_shape_id)
        with self._lock:
            self._annotations[annotation.annotation_id] = annotation
        return annotation

    def edit_annotation(self, annotation_id: str, new_content: str,
                        editor_id: str) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            annotation = self._annotations.get(annotation_id)
        if annotation and annotation.author_id == editor_id:
            annotation.edit(new_content)
            return True
        return False

    def delete_annotation(self, annotation_id: str, requester_id: str) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            annotation = self._annotations.get(annotation_id)
            if annotation and annotation.author_id == requester_id:
                del self._annotations[annotation_id]
                return True
        return False

    def reply_to_annotation(self, annotation_id: str, content: str,
                            author_id: str) -> Optional[AnnotationReply]:
        if not self.is_available():
            return None
        with self._lock:
            annotation = self._annotations.get(annotation_id)
        if annotation:
            return annotation.add_reply(content, author_id)
        return None

    def resolve_annotation(self, annotation_id: str) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            annotation = self._annotations.get(annotation_id)
        if annotation:
            annotation.resolve()
            return True
        return False

    def get_annotations_for_shape(self, shape_id: str) -> List[Annotation]:
        with self._lock:
            return [a for a in self._annotations.values()
                    if a.target_shape_id == shape_id]

    def get_all_annotations(self) -> List[Annotation]:
        with self._lock:
            return list(self._annotations.values())

    def get_unresolved_annotations(self) -> List[Annotation]:
        with self._lock:
            return [a for a in self._annotations.values() if not a.resolved]


# --- Real-Time Collaboration Canvas ---

class CanvasEvent:
    """Represents an event on the canvas for real-time sync."""

    def __init__(self, event_type: str, user_id: str, data: Dict[str, Any]):
        self.event_id: str = str(uuid.uuid4())
        self.event_type: str = event_type
        self.user_id: str = user_id
        self.data: Dict[str, Any] = data
        self.timestamp: datetime = datetime.now()

    def __repr__(self):
        return f"CanvasEvent(type='{self.event_type}', user='{self.user_id}')"


class CanvasSession:
    """Represents a user's active session on the canvas."""

    def __init__(self, user_id: str, username: str):
        self.session_id: str = str(uuid.uuid4())
        self.user_id: str = user_id
        self.username: str = username
        self.cursor_x: float = 0.0
        self.cursor_y: float = 0.0
        self.joined_at: datetime = datetime.now()
        self.last_activity: datetime = datetime.now()
        self.is_active: bool = True

    def update_cursor(self, x: float, y: float):
        self.cursor_x = x
        self.cursor_y = y
        self.last_activity = datetime.now()

    def __repr__(self):
        return f"CanvasSession(user='{self.username}', active={self.is_active})"


class CollaborationCanvas:
    """Shared digital canvas supporting real-time multi-user collaboration."""

    def __init__(self, dependency_manager: DependencyManager, shape_toolkit: ShapeToolkit):
        self._shapes: Dict[str, Shape] = {}
        self._sessions: Dict[str, CanvasSession] = {}
        self._event_log: List[CanvasEvent] = []
        self._listeners: Dict[str, List[callable]] = {}
        self._lock = threading.Lock()
        self._dependency_manager = dependency_manager
        self._shape_toolkit = shape_toolkit
        self.canvas_width: float = 1920.0
        self.canvas_height: float = 1080.0

    def is_available(self) -> bool:
        return self._dependency_manager.is_available("collaboration_canvas")

    def join(self, user_id: str, username: str) -> Optional[CanvasSession]:
        if not self.is_available():
            return None
        session = CanvasSession(user_id, username)
        with self._lock:
            self._sessions[user_id] = session
        self._emit_event("user_joined", user_id, {"username": username})
        return session

    def leave(self, user_id: str) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            session = self._sessions.get(user_id)
            if session:
                session.is_active = False
                del self._sessions[user_id]
                self._emit_event("user_left", user_id, {})
                return True
        return False

    def add_shape(self, shape: Shape) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            self._shapes[shape.shape_id] = shape
        self._emit_event("shape_added", shape.creator_id,
                         {"shape_id": shape.shape_id,
                          "shape_type": shape.shape_type.value})
        return True

    def remove_shape(self, shape_id: str, user_id: str) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            shape = self._shapes.pop(shape_id, None)
        if shape:
            self._emit_event("shape_removed", user_id, {"shape_id": shape_id})
            return True
        return False

    def update_shape(self, shape_id: str, user_id: str, **kwargs) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            shape = self._shapes.get(shape_id)
        if not shape or shape.is_locked:
            return False
        for key, value in kwargs.items():
            if hasattr(shape, key):
                setattr(shape, key, value)
        shape.modified_at = datetime.now()
        self._emit_event("shape_updated", user_id,
                         {"shape_id": shape_id, "updates": kwargs})
        return True

    def lock_shape(self, shape_id: str, user_id: str) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            shape = self._shapes.get(shape_id)
        if shape and not shape.is_locked:
            shape.is_locked = True
            self._emit_event("shape_locked", user_id, {"shape_id": shape_id})
            return True
        return False

    def unlock_shape(self, shape_id: str, user_id: str) -> bool:
        if not self.is_available():
            return False
        with self._lock:
            shape = self._shapes.get(shape_id)
        if shape and shape.is_locked:
            shape.is_locked = False
            self._emit_event("shape_unlocked", user_id, {"shape_id": shape_id})
            return True
        return False

    def get_shape(self, shape_id: str) -> Optional[Shape]:
        with self._lock:
            return self._shapes.get(shape_id)

    def get_all_shapes(self) -> List[Shape]:
        with self._lock:
            return list(self._shapes.values())

    def get_shapes_by_layer(self) -> List[Shape]:
        with self._lock:
            return sorted(self._shapes.values(), key=lambda s: s.layer)

    def get_active_sessions(self) -> List[CanvasSession]:
        with self._lock:
            return [s for s in self._sessions.values() if s.is_active]

    def update_cursor(self, user_id: str, x: float, y: float):
        with self._lock:
            session = self._sessions.get(user_id)
        if session:
            session.update_cursor(x, y)

    def subscribe(self, event_type: str, callback: callable):
        with self._lock:
            if event_type not in self._listeners:
                self._listeners[event_type] = []
            self._listeners[event_type].append(callback)

    def _emit_event(self, event_type: str, user_id: str, data: Dict[str, Any]):
        event = CanvasEvent(event_type, user_id, data)
        self._event_log.append(event)
        listeners = self._listeners.get(event_type, [])
        for callback in listeners:
            try:
                callback(event)
            except Exception:
                pass

    def get_event_log(self, limit: int = 50) -> List[CanvasEvent]:
        return self._event_log[-limit:]


# --- Main Application ---

class CollaborativeDesignSuite:
    """
    Multi-agent collaborative design tool enabling teams of designers to work
    together on a shared digital canvas with real-time updates, shape/texture
    tools, element management, and annotation capabilities.
    """

    def __init__(self):
        # Core dependency manager
        self.dependency_manager = DependencyManager()
        self._initialize_dependencies()

        # Sub-systems
        self.auth = AuthenticationSystem(self.dependency_manager)
        self.shape_toolkit = ShapeToolkit(self.dependency_manager)
        self.canvas = CollaborationCanvas(self.dependency_manager, self.shape_toolkit)
        self.element_manager = ElementManager(self.dependency_manager)
        self.annotation_system = AnnotationSystem(self.dependency_manager)

        # Activate features in dependency order
        self._bootstrap_features()

    def _initialize_dependencies(self):
        """Register all features with their dependency chains."""
        self.dependency_manager.register_feature("authentication", [])
        self.dependency_manager.register_feature(
            "collaboration_canvas", ["authentication"])
        self.dependency_manager.register_feature(
            "shape_tools", ["authentication"])
        self.dependency_manager.register_feature(
            "element_management", ["shape_tools"])
        self.dependency_manager.register_feature(
            "annotation_system", ["collaboration_canvas"])

    def _bootstrap_features(self):
        """Activate and complete features in proper dependency order."""
        feature_order = [
            "authentication",
            "shape_tools",
            "collaboration_canvas",
            "element_management",
            "annotation_system",
        ]
        for feature in feature_order:
            self.dependency_manager.activate_feature(feature)
            self.dependency_manager.complete_feature(feature)

    # --- High-Level API ---

    def register_user(self, username: str, email: str, password: str) -> Optional[User]:
        return self.auth.register(username, email, password)

    def login_user(self, username: str, password: str) -> Optional[str]:
        return self.auth.login(username, password)

    def logout_user(self, token: str) -> bool:
        return self.auth.logout(token)

    def join_canvas(self, token: str) -> Optional[CanvasSession]:
        user = self.auth.validate_session(token)
        if not user:
            return None
        return self.canvas.join(user.user_id, user.username)

    def leave_canvas(self, token: str) -> bool:
        user = self.auth.validate_session(token)
        if not user:
            return False
        return self.canvas.leave(user.user_id)

    def create_shape(self, token: str, shape_type: ShapeType,
                     x: float, y: float, width: float, height: float) -> Optional[Shape]:
        user = self.auth.validate_session(token)
        if not user:
            return None
        shape = self.shape_toolkit.create_shape(shape_type, x, y, width, height, user.user_id)
        if shape:
            self.canvas.add_shape(shape)
        return shape

    def apply_texture(self, token: str, shape_id: str, texture_id: str) -> bool:
        user = self.auth.validate_session(token)
        if not user:
            return False
        shape = self.canvas.get_shape(shape_id)
        if not shape:
            return False
        return self.shape_toolkit.apply_texture_to_shape(shape, texture_id)

    def create_texture(self, token: str, name: str, pattern: str,
                       color: str, opacity: float = 1.0) -> Optional[Texture]:
        user = self.auth.validate_session(token)
        if not user:
            return None
        return self.shape_toolkit.create_texture(name, pattern, color, opacity)

    def group_shapes(self, token: str, group_name: str,
                     shape_ids: List[str]) -> Optional[ElementGroup]:
        user = self.auth.validate_session(token)
        if not user:
            return None
        shapes = [self.canvas.get_shape(sid) for sid in shape_ids]
        shapes = [s for s in shapes if s is not None]
        if not shapes:
            return None
        return self.element_manager.create_group(group_name, user.user_id, shapes)

    def ungroup_shapes(self, token: str, group_id: str) -> bool:
        user = self.auth.validate_session(token)
        if not user:
            return False
        all_shapes = self.canvas.get_all_shapes()
        return self.element_manager.ungroup(group_id, all_shapes)

    def align_shapes(self, token: str, shape_ids: List[str],
                     alignment: AlignmentType) -> bool:
        user = self.auth.validate_session(token)
        if not user:
            return False
        shapes = [self.canvas.get_shape(sid) for sid in shape_ids]
        shapes = [s for s in shapes if s is not None]
        return self.element_manager.align_shapes(shapes, alignment)

    def add_annotation(self, token: str, content: str, x: float, y: float,
                       target_shape_id: Optional[str] = None) -> Optional[Annotation]:
        user = self.auth.validate_session(token)
        if not user:
            return None
        return self.annotation_system.add_annotation(
            content, user.user_id, x, y, target_shape_id)

    def reply_to_annotation(self, token: str, annotation_id: str,
                            content: str) -> Optional[AnnotationReply]:
        user = self.auth.validate_session(token)
        if not user:
            return None
        return self.annotation_system.reply_to_annotation(
            annotation_id, content, user.user_id)

    def resolve_annotation(self, token: str, annotation_id: str) -> bool:
        user = self.auth.validate_session(token)
        if not user:
            return False
        return self.annotation_system.resolve_annotation(annotation_id)

    def get_canvas_state(self) -> Dict[str, Any]:
        """Returns a snapshot of the current canvas state."""
        return {
            "shapes": len(self.canvas.get_all_shapes()),
            "active_users": len(self.canvas.get_active_sessions()),
            "annotations": len(self.annotation_system.get_all_annotations()),
            "unresolved_annotations": len(
                self.annotation_system.get_unresolved_annotations()),
            "groups": len(self.element_manager.list_groups()),
            "textures": len(self.shape_toolkit.list_textures()),
        }

    def get_feature_status(self) -> Dict[str, str]:
        """Returns the status of all features."""
        features = [
            "authentication", "collaboration_canvas",
            "shape_tools", "element_management", "annotation_system"
        ]
        return {
            f: self.dependency_manager.get_status(f).value
            for f in features
        }


# --- Demo / Main ---

def main():
    """Demonstrates the CollaborativeDesignSuite functionality."""
    print("=" * 60)
    print("  CollaborativeDesignSuite - Multi-Agent Design Tool")
    print("=" * 60)

    suite = CollaborativeDesignSuite()

    # Show feature status
    print("\n[Feature Status]")
    for feature, status in suite.get_feature_status().items():
        print(f"  {feature}: {status}")

    # Register users
    print("\n[User Registration]")
    alice = suite.register_user("alice", "alice@design.co", "pass123")
    bob = suite.register_user("bob", "bob@design.co", "pass456")
    print(f"  Registered: {alice}")
    print(f"  Registered: {bob}")

    # Login
    print("\n[Authentication]")
    token_alice = suite.login_user("alice", "pass123")
    token_bob = suite.login_user("bob", "pass456")
    print(f"  Alice logged in: {token_alice is not None}")
    print(f"  Bob logged in: {token_bob is not None}")

    # Join canvas
    print("\n[Canvas Sessions]")
    session_alice = suite.join_canvas(token_alice)
    session_bob = suite.join_canvas(token_bob)
    print(f"  Alice joined canvas: {session_alice is not None}")
    print(f"  Bob joined canvas: {session_bob is not None}")

    # Create shapes
    print("\n[Shape Creation]")
    rect = suite.create_shape(token_alice, ShapeType.RECTANGLE, 100, 100, 200, 150)
    circle = suite.create_shape(token_bob, ShapeType.CIRCLE, 400, 200, 100, 100)
    triangle = suite.create_shape(token_alice, ShapeType.TRIANGLE, 300, 50, 120, 120)
    print(f"  Alice created: {rect}")
    print(f"  Bob created: {circle}")
    print(f"  Alice created: {triangle}")

    # Create and apply texture
    print("\n[Textures]")
    texture = suite.create_texture(token_alice, "Dots", "polka_dot", "#FF5733", 0.8)
    print(f"  Created texture: {texture}")
    if rect:
        applied = suite.apply_texture(token_alice, rect.shape_id, texture.texture_id)
        print(f"  Applied texture to rectangle: {applied}")

    # Group shapes
    print("\n[Element Management]")
    if rect and triangle:
        group = suite.group_shapes(
            token_alice, "Header Elements", [rect.shape_id, triangle.shape_id])
        print(f"  Created group: {group}")

    # Align shapes
    if rect and circle and triangle:
        aligned = suite.align_shapes(
            token_bob,
            [rect.shape_id, circle.shape_id, triangle.shape_id],
            AlignmentType.TOP
        )
        print(f"  Aligned shapes to top: {aligned}")

    # Annotations
    print("\n[Annotations]")
    if rect:
        annotation = suite.add_annotation(
            token_bob, "Consider using a rounded rectangle here",
            rect.x, rect.y, rect.shape_id)
        print(f"  Bob annotated: {annotation}")

        if annotation:
            reply = suite.reply_to_annotation(
                token_alice, annotation.annotation_id,
                "Good idea! I'll update it.")
            print(f"  Alice replied: {reply}")
            suite.resolve_annotation(token_alice, annotation.annotation_id)
            print("  Annotation resolved.")

    # Canvas state
    print("\n[Canvas State Summary]")
    state = suite.get_canvas_state()
    for key, value in state.items():
        print(f"  {key}: {value}")

    # Dependency enforcement demo
    print("\n[Dependency Enforcement Demo]")
    dep_mgr = DependencyManager()
    dep_mgr.register_feature("auth", [])
    dep_mgr.register_feature("canvas", ["auth"])
    dep_mgr.register_feature("annotations", ["canvas"])

    print(f"  Canvas available (auth not done): "
          f"{dep_mgr.is_available('canvas')}")
    dep_mgr.activate_feature("auth")
    dep_mgr.complete_feature("auth")
    print(f"  Auth completed. Canvas activatable: "
          f"{dep_mgr.activate_feature('canvas')}")
    dep_mgr.complete_feature("canvas")
    print(f"  Canvas completed. Annotations activatable: "
          f"{dep_mgr.activate_feature('annotations')}")
    print(f"  Unmet deps for annotations (before canvas): "
          f"{dep_mgr.get_unmet_dependencies('annotations')}")

    print("\n" + "=" * 60)
    print("  Demo Complete")
    print("=" * 60)


if __name__ == "__main__":
    main()
